const DATA_VERSION = '2026-06-14-simplified-map-calendar-v3';
const state = { data: {}, selectedEventId: null, maps: {}, layers: {}, currentLead: null, gdeltArticles: [] };
const $ = (id) => document.getElementById(id);
const COUNTRY_CENTERS = { Germany:[51.16,10.45], Netherlands:[52.13,5.29], 'Czech Republic':[49.82,15.47], Italy:[42.87,12.57], 'United States':[39.5,-98.35], Japan:[36.2,138.25], Canada:[56.13,-106.35], Brazil:[-14.23,-51.93], Thailand:[15.87,100.99], 'South Korea':[36.5,127.8], China:[35.86,104.2], Fiji:[-17.71,178.07], Indonesia:[-0.79,113.92], Laos:[19.86,102.5], Vietnam:[14.06,108.28], Madagascar:[-18.77,46.87], Tanzania:[-6.37,34.89], Namibia:[-22.96,18.49], 'South Africa':[-30.56,22.94], 'Papua New Guinea':[-6.31,143.96], 'New Zealand':[-40.9,174.89], 'Hong Kong':[22.32,114.17], 'mainland China':[35.86,104.2], 'EU internal movements':[50.1,8.7], Caribbean:[18.2,-66.5], 'United Arab Emirates':[23.42,53.85] };
const esc = (value) => String(value ?? '').replace(/[&<>'"]/g, (char) => ({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[char]));

async function loadData(){
  const local = localStorage.getItem('expowatch-edited-data');
  if(local){
    try{
      const parsed = JSON.parse(local);
      if(parsed?.version === DATA_VERSION && parsed?.data){ state.data = parsed.data; state.selectedEventId = state.data.events?.[0]?.id; return; }
      localStorage.removeItem('expowatch-edited-data');
    }catch(error){ localStorage.removeItem('expowatch-edited-data'); }
  }
  const loaded = {};
  for(const name of DATA_FILES){
    try{
      const response = await fetch(`data/${name}.json`, { cache: 'no-store' });
      if(!response.ok) throw new Error(`${name}: ${response.status}`);
      loaded[name] = await response.json();
    }catch(error){
      loaded[name] = BUNDLED_DATA[name];
    }
  }
  const refreshedAirports = localStorage.getItem('expowatch-airports-refresh');
  if(refreshedAirports) loaded.airports = JSON.parse(refreshedAirports);
  state.data = loaded;
  state.selectedEventId = loaded.events[0]?.id;
}

function initTabs(){
  document.querySelectorAll('#tabs button').forEach((button) => {
    button.addEventListener('click', () => showTab(button.dataset.tab));
  });
  window.addEventListener('hashchange', () => showTab(location.hash.replace('#','') || 'dashboard'));
  showTab(location.hash.replace('#','') || 'dashboard');
}
function showTab(tab){
  document.querySelectorAll('#tabs button').forEach((button) => button.classList.toggle('active', button.dataset.tab === tab));
  document.querySelectorAll('.tab-panel').forEach((panel) => panel.classList.toggle('active', panel.id === tab));
  if(location.hash !== `#${tab}`) history.replaceState(null, '', `#${tab}`);
  setTimeout(renderMaps, 80);
}

function eventById(id){ return state.data.events.find((event) => event.id === id); }
function taxonById(id){ return state.data.taxa.find((taxon) => taxon.id === id); }
function airportByIata(iata){ return state.data.airports.find((airport) => airport.iata === iata || airport.id === String(iata || '').toLowerCase()); }
function websitesForEvent(event){ return state.data.websites.filter((website) => event.linked_website_ids?.includes(website.id) || website.related_event_ids?.includes(event.id)); }
function taxaForEvent(event){ return (event.proxy_taxa_ids || []).map(taxonById).filter(Boolean); }
function evidenceForEvent(event){ return state.data.evidence.filter((item) => event.evidence_ids?.includes(item.id) || item.related_event_ids?.includes(event.id)); }
function routesForEvent(event){ return state.data.routes.filter((route) => route.related_event_id === event.id); }

function addDays(date, days){ const d = new Date(`${date}T00:00:00Z`); d.setUTCDate(d.getUTCDate() + days); return d.toISOString().slice(0,10); }
function monitoringWindows(date){
  const today = new Date(); today.setUTCHours(0,0,0,0);
  const ranges = [
    ['Pre-event online monitoring', -56, -14],
    ['Inbound route-risk window', -14, 0],
    ['Event window', 0, 2],
    ['Outbound route-risk window', 0, 7],
    ['Post-event online monitoring', 1, 30]
  ];
  return ranges.map(([label, startOffset, endOffset]) => {
    const start = addDays(date, startOffset); const end = addDays(date, endOffset);
    const status = today >= new Date(`${start}T00:00:00Z`) && today <= new Date(`${end}T00:00:00Z`) ? 'active' : 'scheduled';
    return { label, start, end, status };
  });
}
function timelineHtml(date){
  return `<div class="timeline">${monitoringWindows(date).map((window) => `<div class="window ${window.status === 'active' ? 'active' : ''}"><strong>${esc(window.label)}</strong><div class="mini">${window.start} → ${window.end}</div><span class="status-pill">${esc(window.status)}</span></div>`).join('')}</div>`;
}

function annualCalendarHtml(event){
  const date = event.known_dates[0];
  const year = Number(date.slice(0,4));
  const startImport = new Date(`${addDays(date,-14)}T00:00:00Z`);
  const startEvent = new Date(`${date}T00:00:00Z`);
  const endEvent = new Date(`${addDays(date,2)}T00:00:00Z`);
  const endExport = new Date(`${addDays(date,9)}T00:00:00Z`);
  const dayClass = (day) => {
    const d = new Date(Date.UTC(year, day.month, day.day));
    if(d >= startEvent && d <= endEvent) return 'cal-event';
    if(d >= startImport && d < startEvent) return 'cal-import';
    if(d > endEvent && d <= endExport) return 'cal-export';
    return '';
  };
  const months = Array.from({length:12}, (_,month) => {
    const days = new Date(Date.UTC(year, month+1, 0)).getUTCDate();
    const blanks = new Date(Date.UTC(year, month, 1)).getUTCDay();
    const cells = Array.from({length:blanks}, () => '<span></span>').join('') + Array.from({length:days}, (_,i) => { const day={month,day:i+1}; return `<span class="${dayClass(day)}">${i+1}</span>`; }).join('');
    return `<div class="month-card"><strong>${new Date(Date.UTC(year, month, 1)).toLocaleString('en-US',{month:'short', timeZone:'UTC'})}</strong><div class="month-grid">${cells}</div></div>`;
  }).join('');
  return `<div class="calendar-legend"><span class="cal-import">Import monitoring</span><span class="cal-event">Event days</span><span class="cal-export">Export monitoring</span></div><div class="annual-calendar">${months}</div>`;
}

const EVENT_RISK_WEIGHTS = [
  ['media_iwt_mentions', 18, 'Public media mentions involving IWT, seizure, or smuggling context'],
  ['seizure_history', 14, 'Seizure/report history associated with the event country, event name, or taxa'],
  ['high_risk_taxa_sales', 18, 'High-risk proxy taxa and public sale/handover signals'],
  ['wild_caught_discourse', 14, 'Attendee/forum discourse mentioning wild-caught or source-claim concerns'],
  ['courier_export_links', 10, 'Courier/import-export or document-review linkage'],
  ['international_platform_links', 14, 'International marketplace/forum/platform linkage'],
  ['source_country_overlap', 12, 'Overlap between event corridors and possible source countries']
];
function taxonRiskScore(taxon){
  const iucnMap = { CR: 35, EN: 30, VU: 22, NT: 14, LC: 5, DD: 8, NE: 5, unknown: 5 };
  const cites = String(taxon.cites_appendix || '').toUpperCase();
  const eu = String(taxon.eu_annex || '').toUpperCase();
  const iucn = String(taxon.iucn_category || 'unknown').toUpperCase();
  const protection = String(taxon.range_state_protection || '').toLowerCase();
  let score = iucnMap[iucn] ?? 5;
  if(cites.includes('I')) score += 25; else if(cites.includes('II')) score += 15; else score += 5;
  if(eu.includes('A')) score += 20; else if(eu.includes('B')) score += 10;
  if(/strict|protected|export|permit|restricted|national/.test(protection)) score += 20; else if(protection) score += 8;
  score = Math.min(100, score);
  const category = score >= 80 ? 'critical' : score >= 60 ? 'high' : score >= 35 ? 'medium' : 'low';
  return { score, category };
}
function scoreEvent(event){
  const indicators = event.risk_indicators || {};
  const taxa = taxaForEvent(event);
  const evidence = evidenceForEvent(event);
  const websites = websitesForEvent(event);
  const routes = routesForEvent(event);
  const explanation = [];
  let score = 0;
  EVENT_RISK_WEIGHTS.forEach(([key, weight, label]) => {
    const raw = Math.max(0, Math.min(5, Number(indicators[key] ?? 0)));
    const points = Math.round((raw / 5) * weight);
    score += points;
    if(raw >= 4) explanation.push(`${label}: strong indicator (${raw}/5, +${points}).`);
    else if(raw >= 2) explanation.push(`${label}: moderate indicator (${raw}/5, +${points}).`);
  });
  const taxonScores = taxa.map(taxonRiskScore);
  const criticalTaxa = taxonScores.filter((item) => item.category === 'critical').length;
  const highTaxa = taxonScores.filter((item) => item.category === 'high').length;
  if(criticalTaxa || highTaxa){
    const bonus = Math.min(10, criticalTaxa * 4 + highTaxa * 2);
    score = Math.min(100, score + bonus);
    explanation.push(`${criticalTaxa} critical and ${highTaxa} high taxon-risk records add +${bonus}.`);
  }
  const publicSourceCount = websites.filter((website) => !website.watchlist && website.url).length;
  if(publicSourceCount >= 3) explanation.push(`${publicSourceCount} public linked sources are attached to this profile.`);
  if(routes.length >= 4) explanation.push(`${routes.length} route-risk corridors connect source, transit, or consumer regions for planning review.`);
  if(evidence.length) explanation.push(`${evidence.length} public-safe evidence/news placeholders are linked for verification workflow.`);
  score = Math.max(0, Math.min(100, Math.round(score)));
  const priority = score >= 80 ? 'critical' : score >= 60 ? 'high' : score >= 35 ? 'medium' : 'low';
  const confidencePoints = (event.confidence === 'high' ? 2 : event.confidence === 'medium' ? 1 : 0) + Math.min(2, Math.floor(evidence.length / 2)) + (publicSourceCount >= 3 ? 1 : 0);
  const confidence = confidencePoints >= 4 ? 'high' : confidencePoints >= 2 ? 'medium' : 'low';
  if(!explanation.length) explanation.push('Limited public indicators are attached; keep as baseline monitoring only.');
  return { score, priority, confidence, explanation };
}
function scoreMeter(score, category){ return `<div class="score-meter" aria-label="score ${score}"><span class="score-fill risk-bg-${category}" style="width:${Math.max(4, score)}%"></span></div><div class="mini">Numeric score: <strong>${score}/100</strong></div>`; }
function confidenceBadge(value){ return `<span class="badge confidence">confidence level: ${esc(value)}</span>`; }
function riskBadge(value){ return `<span class="badge risk-${esc(value)}">${esc(value)} priority</span>`; }
function showScoreInfo(){
  const modal = $('scoreInfoModal');
  modal.hidden = false;
  modal.querySelector('.modal-body').innerHTML = `<h3>Event score model</h3><p>Scores are deterministic and client-side. Analysts can adjust the public source data and risk-indicator values in <code>data/events.json</code>.</p><ul>${EVENT_RISK_WEIGHTS.map(([key, weight, label]) => `<li><strong>${esc(key)}</strong> (${weight} pts): ${esc(label)}.</li>`).join('')}</ul><p>Taxa can add a small bonus when IUCN, CITES, EU Annex, and range-state protection fields indicate higher conservation sensitivity.</p><button class="primary-btn" onclick="closeScoreInfo()">Close</button>`;
}
function closeScoreInfo(){ $('scoreInfoModal').hidden = true; }

function renderSummary(){
  const now = new Date();
  const events = [...state.data.events].sort((a,b) => new Date(a.known_dates[0]) - new Date(b.known_dates[0]));
  const upcoming = events.filter((event) => new Date(event.known_dates[0]) >= now);
  const scored = events.map((event) => ({ event, score: scoreEvent(event) })).sort((a,b) => b.score.score - a.score.score);
  const summaryCards = $('summaryCards');
  if(summaryCards) summaryCards.innerHTML = [
    ['Events', state.data.events.length], ['Upcoming events', upcoming.length], ['High / critical', scored.filter((item) => ['high','critical'].includes(item.score.priority)).length], ['Proxy taxa', state.data.taxa.length], ['Linked sources', state.data.websites.length], ['Evidence items', state.data.evidence.length], ['Route corridors', state.data.routes.length]
  ].map(([label, number]) => `<div class="metric"><div class="num">${number}</div><div class="label">${label}</div></div>`).join('');
  const feed = $('upcomingFeed');
  if(feed) feed.innerHTML = upcoming.slice(0, 8).map((event) => `<article class="feed-card"><strong>${esc(event.known_dates[0])}</strong><span>${esc(event.name)}</span><span class="mini">${esc(event.city)}, ${esc(event.country)}</span></article>`).join('');
}

function makeMap(id, options = {}){
  const element = $(id);
  if(!element || element.offsetParent === null) return null;
  if(!window.L){ element.innerHTML = '<div class="map-error">Leaflet could not load from CDN. Check network access or CDN policy.</div>'; return null; }
  if(state.maps[id]){ state.maps[id].invalidateSize(); return state.maps[id]; }
  const map = L.map(id, { preferCanvas: true, ...options }).setView([25, 20], 2);
  L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', { maxZoom: 18, attribution: '&copy; OpenStreetMap contributors' }).addTo(map);
  state.maps[id] = map;
  state.layers[id] = L.layerGroup().addTo(map);
  return map;
}
function priorityColor(priority){ return { low:'#66e0a3', medium:'#f7c948', high:'#ff6b6b', critical:'#d08cff' }[priority] || '#4cc9f0'; }
function clearLayer(id){ const layer = state.layers[id]; if(layer) layer.clearLayers(); }
function addEventMarkers(mapId, map){
  clearLayer(mapId);
  const filter = $('mapPriorityFilter')?.value || 'all';
  const layer = state.layers[mapId];
  state.data.events.filter((event) => filter === 'all' || scoreEvent(event).priority === filter).forEach((event) => {
    const score = scoreEvent(event);
    const taxa = taxaForEvent(event).slice(0,5);
    const marker = L.circleMarker([event.latitude, event.longitude], { radius: score.priority === 'critical' ? 12 : score.priority === 'high' ? 10 : 8, color: '#ffffff', fillColor: priorityColor(score.priority), fillOpacity: .92, weight: 2, className: 'expo-point' }).addTo(layer);
    marker.bindPopup(`<div class="expo-popup"><h3>${esc(event.name)}</h3><p>${esc(event.venue)} · ${esc(event.city)}, ${esc(event.country)}</p><p><strong>Upcoming:</strong> ${esc(event.known_dates[0])}</p><p>${riskBadge(score.priority)} ${confidenceBadge(score.confidence)}</p>${scoreMeter(score.score, score.priority)}<p><strong>Priority species:</strong> ${taxa.map((taxon) => `<em>${esc(taxon.scientific_name)}</em>`).join(', ')}</p><p><strong>Source:</strong> ${event.possible_origin_countries.slice(0,5).map(esc).join(', ')}</p><p><strong>Destination:</strong> ${event.possible_consumer_countries.slice(0,5).map(esc).join(', ')}</p><button onclick="openProfile('${event.id}')">Open profile</button></div>`);
    marker.on('click', () => highlightEventContext(mapId, event));
  });
}
function highlightEventContext(mapId, event){
  const map = state.maps[mapId];
  const layer = state.layers[mapId];
  if(!map || !layer) return;
  layer.eachLayer((item) => { if(item.options?.contextLine || item.options?.countryGlow) layer.removeLayer(item); });
  const addCountry = (country, type) => {
    const center = COUNTRY_CENTERS[country]; if(!center) return;
    L.circleMarker(center, { radius: type === 'origin' ? 7 : 8, color: type === 'origin' ? '#4cc9f0' : '#f7c948', fillColor: type === 'origin' ? '#4cc9f0' : '#f7c948', fillOpacity: .45, weight: 2, countryGlow: true }).addTo(layer).bindTooltip(`${type === 'origin' ? 'Source' : 'Destination'}: ${country}`);
    L.polyline([[event.latitude, event.longitude], center], { color: type === 'origin' ? '#4cc9f0' : '#f7c948', weight: 2, opacity: .42, dashArray: '6 8', contextLine: true }).addTo(layer);
  };
  event.possible_origin_countries.slice(0,5).forEach((country) => addCountry(country, 'origin'));
  event.possible_consumer_countries.slice(0,5).forEach((country) => addCountry(country, 'destination'));
  renderMapInsight(event);
}
function renderMapInsight(event){
  const panel = $('mapInsightPanel'); if(!panel) return;
  const score = scoreEvent(event); const taxa = taxaForEvent(event).slice(0,5);
  panel.innerHTML = `<p class="eyebrow">Selected expo</p><h3>${esc(event.name)}</h3><p>${esc(event.venue)} · ${esc(event.city)}, ${esc(event.country)}</p><p><strong>Most recent / upcoming date:</strong> ${esc(event.known_dates[0])}</p><p>${riskBadge(score.priority)} ${confidenceBadge(score.confidence)}</p>${scoreMeter(score.score, score.priority)}<h4>Top species watchlist</h4><ol>${taxa.map((taxon) => `<li><em>${esc(taxon.scientific_name)}</em> — ${esc(taxon.common_name)}</li>`).join('')}</ol><h4>Highlighted countries</h4><p><strong>Source:</strong> ${event.possible_origin_countries.slice(0,5).map(esc).join(', ')}</p><p><strong>Destination:</strong> ${event.possible_consumer_countries.slice(0,5).map(esc).join(', ')}</p><button class="primary-btn" onclick="openProfile('${event.id}')">Open profile</button>`;
}
function addRouteLines(map){
  const layer = state.layers.routeMap;
  state.data.routes.forEach((route) => {
    const event = eventById(route.related_event_id); if(!event) return;
    const airport = airportByIata(route.destination_airport || route.origin_airport); if(!airport) return;
    L.polyline([[event.latitude, event.longitude], [airport.latitude, airport.longitude]], { color: route.route_type === 'inbound' ? '#4cc9f0' : '#f7c948', weight: 2, opacity: .55 }).addTo(layer);
  });
}
function renderMaps(){
  const dash = makeMap('dashboardMap'); if(dash) addEventMarkers('dashboardMap', dash);
  const route = makeMap('routeMap'); if(route){ clearLayer('routeMap'); addEventMarkers('routeMap', route); addRouteLines(route); }
  setTimeout(() => Object.values(state.maps).forEach((map) => map.invalidateSize()), 120);
}

function renderCalendar(){
  const q = ($('calendarSearch')?.value || '').toLowerCase();
  const events = [...state.data.events].filter((event) => JSON.stringify(event).toLowerCase().includes(q)).sort((a,b) => new Date(a.known_dates[0]) - new Date(b.known_dates[0]));
  $('calendarList').innerHTML = events.map((event) => `<article class="card"><div class="section-head"><div><h3>${esc(event.name)} — ${esc(event.known_dates[0]).slice(0,4)}</h3><p>${esc(event.venue)}, ${esc(event.city)}, ${esc(event.country)}</p></div><button class="ghost-btn" onclick="openProfile('${event.id}')">Open profile</button></div>${annualCalendarHtml(event)}</article>`).join('');
}
function renderProfileSelector(){
  $('profileSelect').innerHTML = state.data.events.map((event) => `<option value="${event.id}">${esc(event.name)}</option>`).join('');
  $('profileSelect').value = state.selectedEventId;
  $('profileSelect').onchange = (event) => { state.selectedEventId = event.target.value; renderProfile(); renderMaps(); };
}
function openProfile(id){ state.selectedEventId = id; showTab('profiles'); renderProfileSelector(); renderProfile(); }
function airlineGoogleSearchUrl(event, direction, country){
  const eventDate = event.known_dates[0];
  const start = direction === 'inbound' ? addDays(eventDate, -14) : eventDate;
  const end = direction === 'inbound' ? eventDate : addDays(eventDate, 7);
  const query = direction === 'inbound'
    ? `${country} to ${event.country} airlines flights ${start} ${end} ${event.city} airport`
    : `${event.country} to ${country} airlines flights ${start} ${end} ${event.city} airport`;
  return `https://www.google.com/search?q=${encodeURIComponent(query)}`;
}
function airlineSearchLinks(event){
  const inbound = event.possible_origin_countries.slice(0,5).map((country) => `<a href="${airlineGoogleSearchUrl(event, 'inbound', country)}" target="_blank" rel="noopener">Inbound: ${esc(country)} → ${esc(event.country)}</a>`).join('');
  const outbound = event.possible_consumer_countries.slice(0,5).map((country) => `<a href="${airlineGoogleSearchUrl(event, 'outbound', country)}" target="_blank" rel="noopener">Outbound: ${esc(event.country)} → ${esc(country)}</a>`).join('');
  return `<div class="flight-links airline-searches"><strong>Dynamic airline searches:</strong>${inbound}${outbound}</div>`;
}
function routeHtml(route){
  return `<div class="route-card"><strong>${esc(route.route_type)}: ${esc(route.origin_country_or_region)} → ${esc(route.destination_country_or_region)}</strong><p class="mini">Window: ${esc(route.timing_window)} · confidence level: ${esc(route.confidence)}</p><p>${esc(route.rationale)}</p><p class="mini">${esc(route.data_basis)}</p><p><strong>${esc(route.caveat)}</strong></p>${flightLookupLinks(route.origin_airport || route.destination_airport, route.destination_airport || route.origin_airport)}</div>`;
}
function flightLookupLinks(originIata, destinationIata){
  const codes = [...new Set([originIata, destinationIata].filter(Boolean))];
  if(!codes.length) return '';
  return `<div class="flight-links"><strong>Public flight/airline lookup:</strong>${codes.map((iata) => `<a href="https://www.flightradar24.com/data/airports/${esc(String(iata).toLowerCase())}" target="_blank" rel="noopener">FR24 ${esc(iata)}</a><a href="https://www.flightconnections.com/flights-from-${esc(String(iata).toLowerCase())}" target="_blank" rel="noopener">Routes from ${esc(iata)}</a><a href="https://www.flightconnections.com/flights-to-${esc(String(iata).toLowerCase())}" target="_blank" rel="noopener">Routes to ${esc(iata)}</a>`).join('')}</div>`;
}
function evidenceHtml(evidence){
  return `<strong>${esc(evidence.title)}</strong><p class="evidence-kind">${esc(evidence.evidence_type)} · confidence level: ${esc(evidence.confidence)}</p><p>${esc(evidence.summary)}</p><p class="mini">Red flags: ${(evidence.extracted_red_flags || []).map(esc).join('; ') || 'none recorded'}</p>`;
}
function disruptionImpacts(){
  return ['Pre-event monitoring may identify sellers before movement.','Event inspection may interrupt handover.','Courier/export checks may disrupt onward movement.','Permit-chain verification may expose false source claims.','Post-event monitoring may identify destination-country buyer networks.'];
}
function renderProfile(){
  const event = eventById(state.selectedEventId); if(!event) return;
  const score = scoreEvent(event), taxa = taxaForEvent(event), websites = websitesForEvent(event), evidence = evidenceForEvent(event), routes = routesForEvent(event);
  $('profileDetail').innerHTML = `<div class="profile-grid"><section class="card"><h3>${esc(event.name)}</h3><p>${esc(event.type)} · ${esc(event.venue)}, ${esc(event.city)}, ${esc(event.country)}</p><p>${riskBadge(score.priority)} ${confidenceBadge(score.confidence)}</p>${scoreMeter(score.score, score.priority)}<button class="score-info-btn" onclick="showScoreInfo()">ⓘ How score is generated</button><p>${esc(event.risk_notes)}</p><p><a href="${esc(event.official_url)}" target="_blank" rel="noopener">Open event/source page</a></p><h4>Dates and monitoring windows</h4>${timelineHtml(event.known_dates[0])}<h4>Annual event calendar</h4>${annualCalendarHtml(event)}<h4>Why flagged</h4><ul>${score.explanation.map((item) => `<li>${esc(item)}</li>`).join('')}</ul></section><section class="card"><h3>Recommended verification</h3><ul><li>Verify taxon identity and source paperwork against declared origin.</li><li>Review public adverts, platform watchlist results, and event handover language before the inbound window.</li><li>Review airline/airport lookup links for legitimate routing context around the event dates.</li></ul><h4>Possible origin countries</h4><p>${event.possible_origin_countries.map(esc).join(', ')}</p><h4>Possible consumer countries</h4><p>${event.possible_consumer_countries.map(esc).join(', ')}</p><h4>Nearby airports</h4><p>${event.nearest_airports.map((iata) => `${esc(iata)} — ${esc(airportByIata(iata)?.name || 'airport lookup')}`).join('<br>')}</p></section></div><div class="profile-grid"><section class="card"><h3>Linked websites and platforms</h3>${websites.map(websiteCard).join('')}</section><section class="card"><h3>High-risk proxy taxa</h3>${taxa.map(taxonCard).join('')}</section></div><div class="profile-grid"><section class="card"><h3>Route-risk corridors and airline searches</h3>${airlineSearchLinks(event)}${routes.map(routeHtml).join('')}</section><section class="card"><h3>Evidence and country news feeds</h3>${rssLinksForEvent(event)}${evidence.map((item) => `<div class="evidence-card">${evidenceHtml(item)}${item.url ? `<a href="${esc(item.url)}" target="_blank" rel="noopener">Open URL</a>` : '<span class="link-muted">No URL recorded</span>'}</div>`).join('')}</section></div><section class="card"><h3>Disruption impacts</h3><ul>${disruptionImpacts().map((item) => `<li>${esc(item)}</li>`).join('')}</ul></section>`;
}

function taxonLookupLinks(taxon){
  const scientific = taxon.scientific_name.replace(/ spp\\.$/, '').replace(/ complex$/, '');
  const parts = scientific.split(/\s+/);
  const genus = encodeURIComponent(parts[0] || scientific);
  const species = encodeURIComponent(parts[1] || '');
  const inat = taxon.inaturalist_url || `https://www.inaturalist.org/taxa/search?q=${encodeURIComponent(scientific)}`;
  const reptileDb = taxon.reptile_database_url || (parts.length > 1 ? `https://reptile-database.reptarium.cz/species?genus=${genus}&species=${species}` : `https://reptile-database.reptarium.cz/advanced_search?submit=Search&taxon=${genus}`);
  const images = `https://www.google.com/search?tbm=isch&q=${encodeURIComponent(scientific + ' reptile identification')}`;
  return `<div class="source-links"><a href="${inat}" target="_blank" rel="noopener">iNaturalist images</a><a href="${reptileDb}" target="_blank" rel="noopener">Reptile Database</a><a href="${images}" target="_blank" rel="noopener">Image search</a></div>`;
}
function taxonCard(taxon){
  const risk = taxonRiskScore(taxon);
  return `<article class="taxon-card no-photo"><div><h4><em>${esc(taxon.scientific_name)}</em></h4><p>${esc(taxon.common_name)} · ${esc(taxon.taxon_group)}</p><p>${riskBadge(risk.category)} ${confidenceBadge(taxon.confidence)}</p>${scoreMeter(risk.score, risk.category)}<p>CITES ${esc(taxon.cites_appendix)} · EU ${esc(taxon.eu_annex)} · IUCN ${esc(taxon.iucn_category || 'unknown')}</p><p><strong>Range-state protection:</strong> ${esc(taxon.range_state_protection || 'not recorded')}</p><p>${esc(taxon.reason_for_inclusion)}</p><p class="mini">${esc(taxon.officer_identification_notes)}</p>${taxonLookupLinks(taxon)}</div></article>`;
}
function renderTaxa(){
  const groups = [...new Set(state.data.taxa.map((taxon) => taxon.taxon_group))];
  $('taxaGroupFilter').innerHTML = '<option value="all">All groups</option>' + groups.map((group) => `<option>${esc(group)}</option>`).join('');
  const cites = [...new Set(state.data.taxa.map((taxon) => taxon.cites_appendix))];
  $('taxaCitesFilter').innerHTML = '<option value="all">All CITES</option>' + cites.map((item) => `<option>${esc(item)}</option>`).join('');
  const update = () => {
    const q = $('taxaSearch').value.toLowerCase(), group = $('taxaGroupFilter').value, citesValue = $('taxaCitesFilter').value, origin = $('taxaOriginFilter').value.toLowerCase(), conf = $('taxaConfidenceFilter').value, basis = $('taxaBasisFilter').value.toLowerCase();
    $('taxaCards').innerHTML = state.data.taxa.filter((taxon) => (!q || [taxon.scientific_name, taxon.common_name].join(' ').toLowerCase().includes(q)) && (group === 'all' || taxon.taxon_group === group) && (citesValue === 'all' || taxon.cites_appendix === citesValue) && (!origin || taxon.possible_origin_countries.join(' ').toLowerCase().includes(origin)) && (conf === 'all' || taxon.confidence === conf) && (!basis || taxon.evidence_basis.toLowerCase().includes(basis))).map((taxon) => `<article class="card">${taxonCard(taxon)}<button class="ghost-btn" onclick="checkGbif('${taxon.id}')">Check GBIF taxonomy/range</button><div id="gbif-${taxon.id}" class="notice"></div></article>`).join('');
  };
  ['taxaSearch','taxaGroupFilter','taxaCitesFilter','taxaOriginFilter','taxaConfidenceFilter','taxaBasisFilter'].forEach((id) => $(id).oninput = update);
  update();
}
async function checkGbif(id){
  const taxon = taxonById(id), element = $(`gbif-${id}`); element.textContent = 'Checking GBIF public API...';
  try{
    const match = await fetch(`https://api.gbif.org/v1/species/match?name=${encodeURIComponent(taxon.scientific_name)}`).then((response) => response.json());
    const occ = match.usageKey ? await fetch(`https://api.gbif.org/v1/occurrence/search?taxon_key=${match.usageKey}&limit=3`).then((response) => response.json()) : null;
    element.innerHTML = `<strong>GBIF biological context:</strong> ${esc(match.scientificName || match.canonicalName || 'No match')} (${esc(match.status || 'unknown status')}). Occurrence sample count returned: ${occ?.results?.length ?? 0}.`;
  }catch(error){ element.innerHTML = 'GBIF lookup failed or was blocked. Use GBIF.org manually for biological context.'; }
}

function websiteCard(website){
  return `<article class="card ${website.watchlist ? 'platform-card' : ''}"><h3>${esc(website.name)}</h3><p>${esc(website.source_type)} · ${confidenceBadge(website.confidence)}</p><p>Related events: ${(website.related_event_ids || []).map((id) => esc(eventById(id)?.name || id)).join(', ') || 'General watchlist'}</p><p>${esc(website.notes)}</p><p class="mini">Last checked: ${esc(website.last_checked)}</p>${website.url ? `<a href="${esc(website.url)}" target="_blank" rel="noopener">Open URL</a>` : '<span class="link-muted">No URL recorded</span>'}</article>`;
}
function renderWebsites(){ const update = () => { const q = ($('websiteSearch').value || '').toLowerCase(); $('websiteCards').innerHTML = state.data.websites.filter((website) => !website.watchlist && JSON.stringify(website).toLowerCase().includes(q)).map(websiteCard).join(''); }; $('websiteSearch').oninput = update; update(); }
function renderPlatforms(){ const update = () => { const q = ($('platformSearch').value || '').toLowerCase(); $('platformCards').innerHTML = state.data.websites.filter((website) => website.watchlist && JSON.stringify(website).toLowerCase().includes(q)).map(websiteCard).join(''); }; $('platformSearch').oninput = update; update(); }
function renderRoutes(){
  $('routeCards').innerHTML = state.data.routes.map((route) => `<article class="card">${routeHtml(route)}<p><strong>Event:</strong> ${esc(eventById(route.related_event_id)?.name || route.related_event_id)}</p><p><strong>Relevant proxy taxa:</strong> ${route.relevant_taxa_ids.map((id) => esc(taxonById(id)?.scientific_name || id)).join(', ')}</p></article>`).join('');
  const select = $('routeEventSelect');
  if(select){ select.innerHTML = state.data.events.map((event) => `<option value="${event.id}">${esc(event.name)}</option>`).join(''); select.onchange = renderFlightLookupPanel; renderFlightLookupPanel(); }
}
function renderFlightLookupPanel(){
  const event = eventById($('routeEventSelect')?.value || state.selectedEventId); if(!event || !$('flightLookupCards')) return;
  $('flightLookupCards').innerHTML = `<h3>Airline and route lookup links for ${esc(event.name)}</h3><p class="mini">Use these public widgets for inbound/outbound airline context around the event window. They are not an automated allegation or private feed.</p><div class="card-grid">${event.nearest_airports.map((iata) => `<article class="card"><h4>${esc(iata)} — ${esc(airportByIata(iata)?.name || 'airport')}</h4>${flightLookupLinks(iata, iata)}<p><strong>Top source/import context:</strong> ${event.possible_origin_countries.map(esc).join(', ')}</p><p><strong>Top consumer/export context:</strong> ${event.possible_consumer_countries.map(esc).join(', ')}</p></article>`).join('')}</div>${airlineSearchLinks(event)}`;
}
async function refreshAirports(){
  const status = $('airportRefreshStatus'); status.textContent = 'Trying OurAirports public CSV...';
  try{
    const url = 'https://davidmegginson.github.io/ourairports-data/airports.csv';
    const csv = await fetch(url).then((response) => { if(!response.ok) throw new Error(response.status); return response.text(); });
    const parsed = Papa.parse(csv, { header: true, skipEmptyLines: true });
    const airports = parsed.data.filter((row) => row.iata_code && ['large_airport','medium_airport'].includes(row.type)).slice(0, 5000).map((row) => ({ id: row.iata_code.toLowerCase(), name: row.name, iata: row.iata_code, icao: row.ident, city: row.municipality, country: row.iso_country, latitude: Number(row.latitude_deg), longitude: Number(row.longitude_deg), airport_type: row.type }));
    localStorage.setItem('expowatch-airports-refresh', JSON.stringify(airports)); state.data.airports = airports; status.textContent = `Loaded ${airports.length} public airport records into browser localStorage. Bundled data remains the fallback.`; renderRoutes(); renderMaps();
  }catch(error){ status.textContent = 'OurAirports refresh failed or was blocked. Continuing with bundled local airport data.'; }
}

function googleNewsRssUrl(query){ return `https://news.google.com/rss/search?q=${encodeURIComponent(query)}&hl=en-US&gl=US&ceid=US:en`; }
function rssLinksForEvent(event){
  const queries = [`${event.country} reptile smuggling`, `${event.country} wildlife seizure reptile`, `${event.name} CITES`, `${event.city} reptile seizure`];
  return `<div class="rss-links"><h4>Country/event news feeds</h4>${queries.map((query) => `<a href="${googleNewsRssUrl(query)}" target="_blank" rel="noopener">RSS: ${esc(query)}</a>`).join('')}</div>`;
}
function renderNewsFeeds(){
  const box = $('rssFeedLinks'); if(!box) return;
  box.innerHTML = state.data.events.map((event) => `<article class="card"><h4>${esc(event.country)} / ${esc(event.name)}</h4>${rssLinksForEvent(event)}</article>`).join('');
}
function renderEvidence(){
  $('gdeltEvent').innerHTML = '<option value="">Event context</option>' + state.data.events.map((event) => `<option value="${event.id}">${esc(event.name)}</option>`).join('');
  $('gdeltSpecies').innerHTML = '<option value="">Species context</option>' + state.data.taxa.map((taxon) => `<option value="${taxon.id}">${esc(taxon.scientific_name)}</option>`).join('');
  $('evidenceCards').innerHTML = state.data.evidence.map((evidence) => `<article class="card">${evidenceHtml(evidence)}${evidence.url ? `<a href="${esc(evidence.url)}" target="_blank" rel="noopener">Open URL</a>` : '<span class="link-muted">No URL recorded</span>'}</article>`).join('');
  renderNewsFeeds();
}
async function searchGdelt(){
  const kw = $('gdeltKeyword').value || 'reptile smuggling'; const event = eventById($('gdeltEvent').value); const taxon = taxonById($('gdeltSpecies').value);
  const queries = [kw, 'wildlife seizure reptile', 'reptile expo']; if(taxon) queries.push(`${taxon.scientific_name} smuggling`); if(event) queries.push(`${event.name} reptile`, `${event.name} CITES`, `${event.city} reptile seizure`, `${event.country} wildlife seizure reptile`);
  const query = `(${queries.map((q) => `"${q}"`).join(' OR ')})`; const params = new URLSearchParams({ query, mode: 'artlist', format: 'json', maxrecords: '20' });
  if($('gdeltStart').value) params.set('startdatetime', $('gdeltStart').value.replaceAll('-','') + '000000'); if($('gdeltEnd').value) params.set('enddatetime', $('gdeltEnd').value.replaceAll('-','') + '235959');
  const url = `https://api.gdeltproject.org/api/v2/doc/doc?${params}`; $('gdeltStatus').innerHTML = `Searching public GDELT DOC API. <a href="${url}" target="_blank">Open query manually</a>`;
  try{
    const data = await fetch(url).then((response) => { if(!response.ok) throw new Error(response.status); return response.json(); });
    const articles = data.articles || [];
    $('gdeltResults').innerHTML = articles.map((article, index) => `<article class="card"><h3>${esc(article.title)}</h3><p class="mini">${esc(article.sourceCountry || article.domain || 'public web')} · ${esc(article.seendate || '')}</p><p>${esc(article.snippet || 'No snippet returned.')}</p><p class="mini">Matched query: ${esc(query)}</p><a href="${esc(article.url)}" target="_blank" rel="noopener">Open result</a><button class="ghost-btn" onclick="draftEvidenceFromGdelt(${index})">Copy result into draft evidence item</button></article>`).join('') || '<p>No public news results returned.</p>';
    state.gdeltArticles = articles;
  }catch(error){ $('gdeltStatus').innerHTML = `GDELT failed due to network/CORS/API availability. Open manually: <a href="${url}" target="_blank">GDELT query URL</a>`; }
}
function draftEvidenceFromGdelt(index){
  const article = state.gdeltArticles?.[index]; if(!article) return;
  $('editEvidenceTitle').value = article.title || 'Public news result';
  $('editEvidenceSummary').value = `Public news result from ${article.domain || 'GDELT'}: ${article.snippet || ''} URL: ${article.url || ''}`;
  showTab('editor');
}

function renderLead(){
  const id = $('leadEventSelect').value || state.selectedEventId; const event = eventById(id); if(!event) return;
  const score = scoreEvent(event), taxa = taxaForEvent(event), websites = websitesForEvent(event), evidence = evidenceForEvent(event), routes = routesForEvent(event);
  const html = `<h3>${esc(event.name)} lead package</h3><p><strong>Product:</strong> Event monitoring lead package.</p><p><strong>Date:</strong> ${esc(event.known_dates[0])}. <strong>Venue:</strong> ${esc(event.venue)}, ${esc(event.city)}, ${esc(event.country)}. <strong>Confidence level:</strong> ${esc(score.confidence)}.</p><h4>Monitoring windows</h4>${timelineHtml(event.known_dates[0])}<h4>Why flagged</h4><p>Score: ${score.score}/100; priority category: ${score.priority}.</p><ul>${score.explanation.map((item) => `<li>${esc(item)}</li>`).join('')}</ul><h4>High-risk proxy taxa</h4><p>${taxa.map((taxon) => esc(taxon.scientific_name)).join(', ')}</p><h4>Possible origin/source countries</h4><p>${event.possible_origin_countries.map(esc).join(', ')}</p><h4>Possible consumer countries</h4><p>${event.possible_consumer_countries.map(esc).join(', ')}</p><h4>Linked websites</h4><ul>${websites.map((website) => `<li>${esc(website.name)} — ${esc(website.source_type)}</li>`).join('')}</ul><h4>Route-risk corridors</h4><ul>${routes.map((route) => `<li>${esc(route.route_type)}: ${esc(route.origin_country_or_region)} to ${esc(route.destination_country_or_region)} (${esc(route.timing_window)}).</li>`).join('')}</ul><h4>Evidence basis</h4><ul>${evidence.map((item) => `<li>${esc(item.title)} — ${esc(item.evidence_type)} — ${esc(item.confidence)}</li>`).join('')}</ul><h4>Recommended verification questions and intervention points</h4><ul><li>Verify source claims, permits, and taxon identity.</li><li>Preserve public evidence with URL and date observed.</li><li>Coordinate route-risk corridor review through authorized workflows.</li></ul><h4>Disruption impacts</h4><ul>${disruptionImpacts().map((item) => `<li>${esc(item)}</li>`).join('')}</ul>`;
  $('leadPackage').innerHTML = html; state.currentLead = { event_id: event.id, generated_at: new Date().toISOString(), score, html };
}
function exportDownload(filename, text, type = 'application/json'){
  const link = document.createElement('a'); link.href = URL.createObjectURL(new Blob([text], { type })); link.download = filename; link.click(); URL.revokeObjectURL(link.href);
}
function renderEditor(){
  $('editEvidenceEvent').innerHTML = state.data.events.map((event) => `<option value="${event.id}">${esc(event.name)}</option>`).join('');
  $('dataPreview').textContent = JSON.stringify(state.data, null, 2).slice(0, 50000);
}
function addEvidence(){
  const eventId = $('editEvidenceEvent').value;
  const item = { id: `local-evidence-${Date.now()}`, title: $('editEvidenceTitle').value || 'Local draft evidence item', evidence_type: 'open web search result', url: '', date_observed: new Date().toISOString().slice(0,10), date_posted: '', related_event_ids: [eventId], related_taxa_ids: eventById(eventId)?.proxy_taxa_ids?.slice(0,2) || [], summary: $('editEvidenceSummary').value || 'Browser-memory analyst draft evidence summary.', extracted_red_flags: ['requires recommended verification'], analyst_notes: 'Local browser draft; export JSON to preserve.', confidence: $('editEvidenceConfidence').value, public_safe: true };
  state.data.evidence.push(item); eventById(eventId)?.evidence_ids?.push(item.id); renderAll(); showTab('editor');
}
function renderAll(){
  renderSummary(); renderCalendar(); renderProfileSelector(); renderProfile(); renderTaxa(); renderWebsites(); renderPlatforms(); renderRoutes(); renderEvidence();
  $('leadEventSelect').innerHTML = state.data.events.map((event) => `<option value="${event.id}">${esc(event.name)}</option>`).join(''); renderLead(); renderEditor();
}
function bindUi(){
  $('calendarSearch').oninput = renderCalendar; $('mapPriorityFilter').onchange = renderMaps; $('refreshAirportsBtn').onclick = refreshAirports; $('gdeltSearchBtn').onclick = searchGdelt; $('generateLeadBtn').onclick = renderLead; $('leadEventSelect').onchange = renderLead; $('printLeadBtn').onclick = () => print(); $('copyLeadBtn').onclick = () => navigator.clipboard?.writeText($('leadPackage').innerText); $('exportLeadBtn').onclick = () => exportDownload('expowatch-lead-package.json', JSON.stringify(state.currentLead, null, 2)); $('addEvidenceBtn').onclick = addEvidence; $('saveLocalBtn').onclick = () => { localStorage.setItem('expowatch-edited-data', JSON.stringify({ version: DATA_VERSION, data: state.data })); alert('Saved to localStorage.'); }; $('exportDataBtn').onclick = () => exportDownload('expowatch-edited-data.json', JSON.stringify(state.data, null, 2)); $('importDataBtn').onclick = () => { try{ state.data = JSON.parse($('importDataText').value); renderAll(); alert('Imported into browser memory.'); }catch(error){ alert('Invalid JSON.'); } }; $('resetDataBtn').onclick = $('resetLocalBtn').onclick = () => { localStorage.removeItem('expowatch-edited-data'); location.reload(); }; $('printPageBtn').onclick = () => print();
}

